-- calc_users_activity_level
-- Field: Users.ActivityLevel
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_users_activity_level(p_user_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN (calc_users_wind_count(p_user_id))::NUMERIC = 0 THEN ('idle')::text ELSE (CASE WHEN (calc_users_wind_count(p_user_id))::NUMERIC <= 2 THEN ('casual')::text ELSE ('busy')::text END)::text END)::text;
$$ LANGUAGE sql STABLE;

