-- calc_gear_trains_timer_escapement_hz
-- Field: GearTrains.TimerEscapementHz
-- Type: lookup | DataType: number | Returns: NUMERIC
-- Lookup: EscapementBaseHz from related Timers


CREATE OR REPLACE FUNCTION calc_gear_trains_timer_escapement_hz(p_gear_train_id TEXT)
RETURNS NUMERIC AS $$
  SELECT (SELECT escapement_base_hz::numeric FROM timers WHERE timer_id = (SELECT in_timer FROM gear_trains WHERE gear_train_id = p_gear_train_id));
$$ LANGUAGE sql STABLE;

-- calc_gear_trains_output_shaft_rpm
-- Field: GearTrains.OutputShaftRPM
-- Type: calculated | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_gear_trains_output_shaft_rpm(p_gear_train_id TEXT)
RETURNS NUMERIC AS $$
  SELECT ((COALESCE(CASE WHEN ((COALESCE(CASE WHEN (calc_gear_trains_timer_escapement_hz(p_gear_train_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_gear_trains_timer_escapement_hz(p_gear_train_id))::numeric ELSE NULL END, 0) * COALESCE(60, 0)))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((COALESCE(CASE WHEN (calc_gear_trains_timer_escapement_hz(p_gear_train_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_gear_trains_timer_escapement_hz(p_gear_train_id))::numeric ELSE NULL END, 0) * COALESCE(60, 0)))::numeric ELSE NULL END, 0) / NULLIF(COALESCE(CASE WHEN ((SELECT reduction_ratio FROM gear_trains WHERE gear_train_id = p_gear_train_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((SELECT reduction_ratio FROM gear_trains WHERE gear_train_id = p_gear_train_id))::numeric ELSE NULL END, 0), 0)))::numeric;
$$ LANGUAGE sql STABLE;

