-- calc_cooks_status
-- Field: Cooks.Status
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_cooks_status(p_cook_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN calc_cooks_timer_has_rung(p_cook_id) THEN ('Done')::text ELSE (CASE WHEN calc_cooks_timer_is_armed(p_cook_id) THEN ('Cooking')::text ELSE ('Pending')::text END)::text END)::text;
$$ LANGUAGE sql STABLE;

-- calc_cooks_timer_can_cover_recipe
-- Field: Cooks.TimerCanCoverRecipe
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_cooks_timer_can_cover_recipe(p_cook_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (calc_cooks_timer_wind_duration(p_cook_id) >= calc_cooks_recommended_minutes(p_cook_id))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_cooks_suitability_verdict
-- Field: Cooks.SuitabilityVerdict
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_cooks_suitability_verdict(p_cook_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN calc_cooks_timer_wind_duration(p_cook_id) < calc_cooks_recommended_minutes(p_cook_id) THEN ('insufficient')::text ELSE (CASE WHEN calc_cooks_timer_wind_duration(p_cook_id) > (COALESCE(CASE WHEN (calc_cooks_recommended_minutes(p_cook_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_cooks_recommended_minutes(p_cook_id))::numeric ELSE NULL END, 0) * COALESCE(3, 0)) THEN ('overkill')::text ELSE ('appropriate')::text END)::text END)::text;
$$ LANGUAGE sql STABLE;

-- calc_recipes_times_used_today
-- Field: Recipes.TimesUsedToday
-- Type: aggregation | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_recipes_times_used_today(p_recipe_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COUNT(*) FROM cooks WHERE follows_recipe = (SELECT NULLIF(recipe_id, '') FROM recipes WHERE recipe_id = p_recipe_id)))::integer;
$$ LANGUAGE sql STABLE;

-- calc_recipes_duration_category
-- Field: Recipes.DurationCategory
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_recipes_duration_category(p_recipe_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN ((SELECT recommended_minutes FROM recipes WHERE recipe_id = p_recipe_id))::NUMERIC < 5 THEN ('quick')::text ELSE (CASE WHEN ((SELECT recommended_minutes FROM recipes WHERE recipe_id = p_recipe_id))::NUMERIC < 15 THEN ('short')::text ELSE (CASE WHEN ((SELECT recommended_minutes FROM recipes WHERE recipe_id = p_recipe_id))::NUMERIC < 45 THEN ('medium')::text ELSE ('long')::text END)::text END)::text END)::text;
$$ LANGUAGE sql STABLE;

-- calc_recipes_cooking_temp_profile
-- Field: Recipes.CookingTempProfile
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_recipes_cooking_temp_profile(p_recipe_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN ((SELECT ideal_temperature_c FROM recipes WHERE recipe_id = p_recipe_id))::NUMERIC >= 200 THEN ('hot oven')::text ELSE (CASE WHEN ((SELECT ideal_temperature_c FROM recipes WHERE recipe_id = p_recipe_id))::NUMERIC >= 150 THEN ('warm oven')::text ELSE (CASE WHEN ((SELECT ideal_temperature_c FROM recipes WHERE recipe_id = p_recipe_id))::NUMERIC >= 90 THEN ('boiling')::text ELSE ('low')::text END)::text END)::text END)::text;
$$ LANGUAGE sql STABLE;

-- calc_recipes_avg_timer_capacity
-- Field: Recipes.AvgTimerCapacity
-- Type: aggregation | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_recipes_avg_timer_capacity(p_recipe_id TEXT)
RETURNS NUMERIC AS $$
  SELECT ((SELECT COALESCE(AVG((calc_cooks_timer_wind_duration(cook_id))::numeric), 0) FROM cooks WHERE follows_recipe = p_recipe_id))::numeric;
$$ LANGUAGE sql STABLE;

-- calc_recipes_total_timer_capacity
-- Field: Recipes.TotalTimerCapacity
-- Type: aggregation | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_recipes_total_timer_capacity(p_recipe_id TEXT)
RETURNS NUMERIC AS $$
  SELECT ((SELECT COALESCE(SUM((calc_cooks_timer_wind_duration(cook_id))::numeric), 0) FROM cooks WHERE follows_recipe = p_recipe_id))::numeric;
$$ LANGUAGE sql STABLE;

-- calc_recipes_assignment_verdict
-- Field: Recipes.AssignmentVerdict
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_recipes_assignment_verdict(p_recipe_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN (calc_recipes_times_used_today(p_recipe_id))::NUMERIC = 0 THEN ('unused')::text ELSE (CASE WHEN calc_recipes_avg_timer_capacity(p_recipe_id) < (SELECT recommended_minutes FROM recipes WHERE recipe_id = p_recipe_id) THEN ('under-provisioned')::text ELSE (CASE WHEN calc_recipes_avg_timer_capacity(p_recipe_id) > (COALESCE(CASE WHEN ((SELECT recommended_minutes FROM recipes WHERE recipe_id = p_recipe_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((SELECT recommended_minutes FROM recipes WHERE recipe_id = p_recipe_id))::numeric ELSE NULL END, 0) * COALESCE(3, 0)) THEN ('over-provisioned')::text ELSE ('well-matched')::text END)::text END)::text END)::text;
$$ LANGUAGE sql STABLE;

