-- calc_kitchens_operational_status
-- Field: Kitchens.OperationalStatus
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_kitchens_operational_status(p_kitchen_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN (calc_kitchens_cooks_cooking(p_kitchen_id))::NUMERIC = 0 THEN ('quiet')::text ELSE (CASE WHEN (calc_kitchens_cooks_cooking(p_kitchen_id))::NUMERIC >= 3 THEN ('busy')::text ELSE ('active')::text END)::text END)::text;
$$ LANGUAGE sql STABLE;

